import logging
from flake8 import Plugin
from flake8 import options
from flake8 import messages
from flake8 import utils

class LoggingFormatChecker(Plugin):
    name = 'logging-format'
    version = '0.1'
    log_level = logging.DEBUG

    def add_options(self, parser):
        group = options.input_group(
            'logging',
            'check for logging format strings',
            parser
        )
        group.add_argument(
            '--logging-format',
            action='store_true',
            help='check for logging format strings'
        )

    def check_logging_format(self, tree):
        for node in tree.walker():
            if isinstance(node, utils.Name) and node.name == 'logging':
                for child in node.get_children():
                    if isinstance(child, utils.Call) and child.func.name == 'format':
                        for arg in child.args:
                            if isinstance(arg, utils.Str):
                                if not arg.value.startswith('%'):
                                    yield messages.Message(
                                        self.line_number(node),
                                        self.column_number(node),
                                        'W9001',
                                        'logging format string should start with %'
                                    )

    def run(self):
        if self.options.logging_format:
            tree = self.parse()
            self.check_logging_format(tree)
        else:
            tree = self.parse()
            super().run(tree)

if __name__ == '__main__':
    plugin = LoggingFormatChecker()
    plugin.run()
```

