import ast
from flake8 import Plugin
from flake8 import options

class BlindExceptPlugin(Plugin):
    name = 'flake8-blind-except'
    version = '1.0'
    message = 'Blind except statement found'

    def match(self, tree):
        return any(isinstance(node, ast.Try) for node in ast.walk(tree))

    def run(self, tree, filename):
        for node in ast.walk(tree):
            if isinstance(node, ast.Try):
                for handler in node.handlers:
                    if isinstance(handler, ast.ExceptHandler):
                        if not handler.type:
                            self.add_error(self.message, node.lineno, node.col_offset)

def main():
    parser = options.get_parser()
    args = parser.parse_args()
    plugin = BlindExceptPlugin()
    plugin.run_tree(ast.parse(open(args.filename).read()))

if __name__ == '__main__':
    main()
```

